const ProductsPage = () => {
	const [searchQuery, setSearchQuery] = useState("");
	const [currentPage, setCurrentPage] = useState(1);
	const productsPerPage = 12;

	// Filter products based on search
	const filteredProducts = allProducts.filter((product) =>
		product.name.toLowerCase().includes(searchQuery.toLowerCase())
	);

	// Calculate pagination
	const totalPages = Math.ceil(filteredProducts.length / productsPerPage);
	const indexOfLastProduct = currentPage * productsPerPage;
	const indexOfFirstProduct = indexOfLastProduct - productsPerPage;
	const currentProducts = filteredProducts.slice(indexOfFirstProduct, indexOfLastProduct);

	// Reset to page 1 when search changes
	const handleSearch = (e) => {
		setSearchQuery(e.target.value);
		setCurrentPage(1);
	};

	const goToPage = (page) => {
		setCurrentPage(page);
		window.scrollTo({ top: 0, behavior: 'smooth' });
	};

	return (
		<div className="bg-gray-50 min-h-screen font-sans">
			{/* Header Banner */}
			<div className="bg-green-800 py-12 md:py-20 text-center text-white relative overflow-hidden">
				<div className="absolute top-0 left-0 w-32 h-32 bg-white opacity-5 rounded-full -translate-x-10 -translate-y-10"></div>
				<div className="absolute bottom-0 right-0 w-48 h-48 bg-yellow-500 opacity-10 rounded-full translate-x-10 translate-y-10"></div>

				<h1 className="text-4xl md:text-5xl font-bold mb-4 relative z-10">
					Our Products
				</h1>
				<p className="text-green-100 max-w-xl mx-auto text-lg relative z-10">
					Explore our range of high-quality agricultural solutions designed to maximize your yield.
				</p>
			</div>

			<div className="container mx-auto px-4 py-12">
				{/* Search Bar */}
				<div className="max-w-2xl mx-auto mb-8">
					<div className="relative">
						<input
							type="text"
							placeholder="Search products..."
							value={searchQuery}
							onChange={handleSearch}
							className="w-full pl-12 pr-4 py-4 border border-gray-300 rounded-xl focus:ring-2 focus:ring-green-500 focus:outline-none transition-all shadow-sm"
						/>
						<Search className="absolute left-4 top-4 text-gray-400" size={20} />
					</div>
				</div>

				{/* Results Info */}
				<div className="mb-6 text-gray-600 text-sm flex justify-between items-center">
					<span>
						Showing {indexOfFirstProduct + 1}-{Math.min(indexOfLastProduct, filteredProducts.length)} of {filteredProducts.length} products
					</span>
					<span className="text-gray-500">
						Page {currentPage} of {totalPages}
					</span>
				</div>

				{/* Product Grid */}
				{currentProducts.length > 0 ? (
					<>
						<div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
							{currentProducts.map((product) => (
								<div
									key={product.id}
									className="bg-white rounded-xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 border border-gray-100 group flex flex-col cursor-pointer"
								>
									{/* Product Image */}
									<div className="relative h-56 bg-gray-100 overflow-hidden">
										<img
											src={product.image}
											alt={product.name}
											className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
										/>
										<span className="absolute top-3 left-3 bg-yellow-400 text-black text-xs font-bold px-2 py-1 rounded shadow-sm">
											{product.category}
										</span>
									</div>

									{/* Product Info */}
									<div className="p-5 flex flex-col flex-grow">
										<h3 className="text-lg font-bold text-gray-800 mb-2 group-hover:text-green-700 transition-colors">
											{product.name}
										</h3>
										<p className="text-gray-500 text-sm mb-4 line-clamp-2 flex-grow">
											{product.description}
										</p>

										{/* Rating */}
										<div className="flex items-center gap-1">
											{[1, 2, 3, 4, 5].map((star) => (
												<Star
													key={star}
													size={14}
													className="text-yellow-400 fill-yellow-400"
												/>
											))}
											<span className="text-xs text-gray-400 ml-1">(45 reviews)</span>
										</div>
									</div>
								</div>
							))}
						</div>

						{/* Pagination Controls */}
						{totalPages > 1 && (
							<div className="mt-12 flex justify-center items-center gap-2">
								<button
									onClick={() => goToPage(currentPage - 1)}
									disabled={currentPage === 1}
									className="p-2 rounded-lg border border-gray-300 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 transition-colors"
								>
									<ChevronLeft size={20} />
								</button>

								{/* Page Numbers */}
								<div className="flex gap-2">
									{[...Array(totalPages)].map((_, index) => {
										const pageNumber = index + 1;
										// Show first page, last page, current page, and pages around current
										if (
											pageNumber === 1 ||
											pageNumber === totalPages ||
											(pageNumber >= currentPage - 1 && pageNumber <= currentPage + 1)
										) {
											return (
												<button
													key={pageNumber}
													onClick={() => goToPage(pageNumber)}
													className={`px-4 py-2 rounded-lg font-medium transition-all ${
														currentPage === pageNumber
															? 'bg-green-700 text-white shadow-md'
															: 'border border-gray-300 hover:bg-gray-50'
													}`}
												>
													{pageNumber}
												</button>
											);
										} else if (
											pageNumber === currentPage - 2 ||
											pageNumber === currentPage + 2
										) {
											return <span key={pageNumber} className="px-2 py-2">...</span>;
										}
										return null;
									})}
								</div>

								<button
									onClick={() => goToPage(currentPage + 1)}
									disabled={currentPage === totalPages}
									className="p-2 rounded-lg border border-gray-300 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 transition-colors"
								>
									<ChevronRight size={20} />
								</button>
							</div>
						)}
					</>
				) : (
					/* Empty State */
					<div className="bg-white p-12 text-center rounded-xl border border-dashed border-gray-300">
						<div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
							<Search className="text-gray-400" size={32} />
						</div>
						<h3 className="text-lg font-bold text-gray-800">No products found</h3>
						<p className="text-gray-500">Try adjusting your search.</p>
						<button
							onClick={() => setSearchQuery("")}
							className="mt-4 text-green-700 font-semibold hover:underline"
						>
							Clear search
						</button>
					</div>
				)}
			</div>
		</div>
	);
};

export default ProductsPage;